sp_widget.client_script:
function($scope, $http, spUtil) {
    var c = this;
    c.lessons = [];
    c.submitting = false;
    c.message = '';
    c.messageType = '';

    c.setRating = function(lesson, rating) {
        lesson.selectedRating = rating;
    };

    c.submitFeedback = function(lesson) {
        if (!lesson.selectedRating) {
            spUtil.addErrorMessage('Please select a rating.');
            return;
        }
        c.submitting = true;
        c.server.get({
            action: 'submitFeedback',
            lessonId: lesson.sys_id,
            rating: lesson.selectedRating,
            feedback: lesson.feedbackText || ''
        }).then(function(r) {
            c.submitting = false;
            if (r.data.success) {
                lesson.submitted = true;
                c.messageType = 'success';
                c.message = 'Thank you for your feedback!';
            } else {
                spUtil.addErrorMessage(r.data.error);
            }
        });
    };
}

sp_widget.css:
.feedback-widget h3 {
    font-size: 18px;
    margin-bottom: 16px;
    font-weight: 600;
}
.lesson-card {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 16px;
    margin-bottom: 16px;
}
.lesson-card .lesson-meta {
    font-size: 13px;
    color: #6c757d;
    margin-bottom: 12px;
}
.lesson-card .lesson-meta strong {
    color: #212529;
}
.star-row {
    display: flex;
    gap: 6px;
    margin-bottom: 12px;
}
.star-btn {
    background: none;
    border: none;
    font-size: 28px;
    cursor: pointer;
    color: #dee2e6;
    padding: 0;
    line-height: 1;
    transition: color 0.1s;
}
.star-btn.active {
    color: #f0a500;
}
.star-btn:hover {
    color: #f0a500;
}
.feedback-done {
    color: #28a745;
    font-weight: 600;
    font-size: 14px;
}
.no-lessons {
    color: #6c757d;
    font-style: italic;
    padding: 20px 0;
    text-align: center;
}

sp_widget.script:
(function() {
    var action = input ? input.action : null;

    if (!action) {
        // Load completed lessons for current user without feedback
        var gr = new GlideRecord('x_608645_my_comp_0_lesson');
        gr.addQuery('student', gs.getUserID());
        gr.addQuery('status', 'completed');
        gr.addQuery('feedback_rating', '');
        gr.orderByDesc('start_time');
        gr.query();

        data.lessons = [];
        while (gr.next()) {
            data.lessons.push({
                sys_id: gr.getUniqueValue(),
                teacher: gr.teacher.getDisplayValue(),
                start_time: gr.getDisplayValue('start_time'),
                end_time: gr.getDisplayValue('end_time'),
                summary: gr.getValue('summary') || ''
            });
        }

    } else if (action === 'submitFeedback') {
        try {
            var gr = new GlideRecord('x_608645_my_comp_0_lesson');
            if (gr.get(input.lessonId) && gr.getValue('student') == gs.getUserID()) {
                gr.setValue('feedback_rating', input.rating);
                gr.setValue('student_feedback', input.feedback);
                gr.update();
                data.success = true;
            } else {
                data.success = false;
                data.error = 'Lesson not found or access denied.';
            }
        } catch (e) {
            data.success = false;
            data.error = e.toString();
        }
    }
})();
